CREATE VIEW `dwd_video_short_video_watch_view` (`dt` COMMENT "日期，根据create_time转换而来", `create_time` COMMENT "服务端数据创建时间", `user_id` COMMENT "用户id", `lang_id` COMMENT "语言", `series_id` COMMENT "剧id", `epis_id` COMMENT "集id", `epis_num` COMMENT "第几集", `ts` COMMENT "app时间戳（客户端）", `sr_createtime` COMMENT "starrocks数据注入时间", `sr_updatetime` COMMENT "starrocks数据更新时间")
